+  return {
+    token: {
+      type: 'expectedErrors',
+      entries,
+      raw: tokenText,
+    },
+    parseError,
+  };
+}
+
+function parseFenceMetadata(metaText) {
+  if (!metaText) {
+    return {
+      leading: '',
+      trailing: '',
+      tokens: [],
+      parseError: false,
+      hadDuplicateExpectedErrors: false,
+    };
+  }
