+
+function stringifyFenceMetadata(metadata) {
+  if (!metadata.tokens.length) {
+    return '';
+  }
+
+  const parts = metadata.tokens
+    .map((token) => {
+      if (token.type === 'expectedErrors') {
+        return stringifyExpectedErrorsToken(token);
+      }
+      return token.raw;
+    })
+    .filter(Boolean);
