+  buildFenceLine,
+  getCompilerExpectedLines,
+  getSortedUniqueNumbers,
+  hasCompilerEntry,
+  metadataEquals,
+  metadataHasExpectedErrorsToken,
+  parseFenceMetadata,
+  removeCompilerExpectedLines,
+  setCompilerExpectedLines,
+  stringifyFenceMetadata,
+};
